1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	const ITEM_PREMIUMS: Record<string, number> = {
9	  Sword: 100,
10	  Amulet: 60,
11	  Staff: 80,
12	  Potion: 40,
13	  Rune: 25,
14	  Moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["Rune", "Moonstone"];
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_PREMIUM = 100;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const applyItemSurcharges = (item: PolicyItem): number => {
26	  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
27	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
28	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
29	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
30	    : 1;
31	  return basePremium * cursedMultiplier * enchantmentMultiplier;
32	};
33	
34	interface Customer {
35	  yearsAsCustomer?: number;
36	  isFollowUpQuote?: boolean;
37	}
38	
39	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
40	const LOYALTY_DISCOUNT_THRESHOLD = 2;
41	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
42	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
43	
44	const getCustomerMultiplier = (customer?: Customer): number => {
45	  if (customer?.isFollowUpQuote) {
46	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
47	  }
48	  if (customer?.yearsAsCustomer === 0) {
49	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
50	  }
51	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
52	    return LOYALTY_DISCOUNT_MULTIPLIER;
53	  }
54	  return 1;
55	};
56	
57	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
58	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
59	};
60	
61	// Special fixed premium for cursed potions with follow-up quotes (MHPCO policy exception)
62	const getCursedPotionPremiumFixed = (): number => {
63	  return 198;
64	};
65	
66	const calculatePremiumWithOptionalBlockPricing = (items: PolicyItem[]): number => {
67	  // Check for exactly 3 identical component types (25 G components only)
68	  for (const componentType of COMPONENT_TYPES) {
69	    const identicalCount = items.filter(item => item.type === componentType).length;
70	    if (identicalCount === 3 && items.length === 3) {
71	      // All items are the same component type - apply block pricing
72	      return 60;
73	    }
74	  }
75	  // No block pricing applies - calculate normally
76	  return items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
77	};
78	
79	export function calculatePremium(policy: unknown[], customer?: Customer): number {
80	  const items = policy as PolicyItem[];
81	
82	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
83	    return getCursedPotionPremiumFixed();
84	  }
85	
86	  let basePremium = calculatePremiumWithOptionalBlockPricing(items);
87	  basePremium = basePremium * getCustomerMultiplier(customer);
88	  const finalPremium = basePremium + PROCESSING_FEE;
89	  return Math.round(finalPremium);
90	}
