92	const DEDUCTIBLE_PER_EVENT = 100;
93	const DRAGON_MATERIAL_TYPE = "DragonSword";
94	
95	const isDragonMaterialItem = (items: PolicyItem[]): boolean => {
96	  return items.length > 0 && items[0].type === DRAGON_MATERIAL_TYPE;
97	};
