99	export function processClaim(policy: unknown[], damages: unknown[], claimAmount: unknown): unknown {
100	  const items = policy as PolicyItem[];
101	  const damageArray = damages as number[];
102	  const claimDamage = damageArray[0];
103	
104	  if (isDragonMaterialItem(items)) {
105	    return claimDamage;
106	  }
107	
108	  let reimbursement = claimDamage;
109	
110	  // Apply 50% reduction for enchantment >= 8
111	  if (items[0].enchantment !== undefined && items[0].enchantment >= 8) {
112	    reimbursement = reimbursement * 0.5;
113	  }
114	
115	  return reimbursement - DEDUCTIBLE_PER_EVENT;
116	}
